parameters.jsCode:
const b = ($input.first().json.body) || {};
return [{
  json: {
    guestId: b.guest_id || b.from || 'unknown',
    channel: String(b.channel || 'whatsapp').toLowerCase(),
    sender: b.from || '',
    guestName: b.profile_name || b.name || 'Guest',
    message: String(b.text || b.message || '').trim(),
    receivedAt: new Date().toISOString()
  }
}];

